fn build_cli() -> Command {
    Command::new("executable")
        .about("Futuristic take on hexdump, made in Rust.\n")
        .version("hx 0.7.0")
        .disable_version_flag(true)
        .arg(
            Arg::new("cols")
                .short('c')
                .long("cols")
                .value_name("columns")
                .help("Set column length")
                .num_args(1),
        )
        .arg(
            Arg::new("len")
                .short('l')
                .long("len")
                .value_name("len")
                .help("Set <len> bytes to read")
                .num_args(1),
        )
        .arg(
            Arg::new("format")
                .short('f')
                .long("format")
                .value_name("format")
                .help("Set format of octet: Octal (o), LowerHex (x), UpperHex (X), Binary (b)")
                .num_args(1)
                .value_parser(["o", "x", "X", "b"]),
        )
        .arg(
            Arg::new("color")
                .short('t')
                .long("color")
                .value_name("color")
                .help("Set color tint terminal output. 0 to disable, 1 to enable")
                .num_args(1)
                .value_parser(["0", "1"]),
